import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String userInput = scanner.nextLine();

        // Ensure that the length of userInput does not exceed the size of the buffer
        if (userInput.length() > 10) {
            System.out.println("Input exceeds buffer size. Exiting...");
            return;
        }

        char[] buffer = new char[10];

        // Copy user input into buffer with bounds checking
        for (int i = 0; i < userInput.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = userInput.charAt(i);
            } else {
                break; // Prevent buffer overflow by breaking out of loop
            }
        }

        System.out.println("Secure buffer usage implemented successfully!");
    }
}

